  1→import './login.css';
  2→import React, { useEffect, useState } from "react";
  3→import { useNavigate } from "react-router-dom";
  4→import { useAuth } from '../../Context/useAuth.js';
  5→import supabase from '../../utils/supabaseClient.js';
  6→
  7→const LoginPage = () => {
  8→    const [showPass, setShowPass] = useState(false);
  9→    const [password, setPassword] = useState('');
 10→    const [email, setEmail] = useState('');
 11→    const [errorMessage, setErrorMessage] = useState('');
 12→    const [successMessage, setSuccessMessage] = useState('');
 13→    const [isLoading, setIsLoading] = useState(false);
 14→
 15→    const { session } = useAuth();
 16→    const navigate = useNavigate();
 17→
 18→    const handleShowPass = (e) => {
 19→        e.preventDefault();
 20→        setShowPass((prev) => !prev);
 21→    };
 22→
 23→    const handleNavigate = (e) => {
 24→        e.preventDefault();
 25→        navigate('/signUp');
 26→    };
 27→
 28→    const handleLogin = async (e) => {
 29→        e.preventDefault();
 30→        setErrorMessage('');
 31→        setSuccessMessage('');
 32→        setIsLoading(true);
 33→        try {
 34→            const { error } = await supabase.auth.signInWithPassword({ email, password });
 35→            if (error) {
 36→                setIsLoading(false);
 37→                return setErrorMessage(error.message);
 38→            }
 39→            setSuccessMessage('Signed in. Redirecting...');
 40→            setTimeout(() => navigate('/home'), 600);
 41→        } catch (error) {
 42→            console.error('Error during sign-in:', error.message);
 43→            setErrorMessage(error.message);
 44→            setIsLoading(false);
 45→        }
 46→    };
 47→
 48→    useEffect(() => {
 49→        if (session) {
 50→            navigate('/home');
 51→        }
 52→    }, [session, navigate]);
 53→
 54→    const isSubmitDisabled = !email || !password || isLoading;
 55→
 56→    return (
 57→        <div className='auth-shell login-shell'>
 58→            <section className='auth-panel'>
 59→                <div className='brand'>Iskrib</div>
 60→                <h1 className='panel-title'>A calm place to write, reflect, and share.</h1>
 61→                <p className='panel-copy'>
 62→                    Keep your thoughts in one quiet space. Publish when you are ready.
 63→                </p>
 64→                <div className='panel-details'>
 65→                    Minimalist editor · Private drafts · Thoughtful community
 66→                </div>
 67→            </section>
 68→
 69→            <section className='auth-form-panel'>
 70→                <div className='auth-form-card'>
 71→                    <header>
 72→                        <h2 className='form-title'>Welcome back</h2>
 73→                        <p className='form-subtitle'>Sign in to continue your writing journey.</p>
 74→                    </header>
 75→
 76→                    <form className='auth-form' onSubmit={handleLogin} aria-busy={isLoading ? 'true' : 'false'}>
 77→                        <div className='form-field'>
 78→                            <label htmlFor='login-email'>Email</label>
 79→                            <input
 80→                                id='login-email'
 81→                                type='email'
 82→                                autoComplete='email'
 83→                                value={email}
 84→                                onChange={(e) => setEmail(e.target.value)}
 85→                                placeholder='you@example.com'
 86→                                className='auth-input'
 87→                                required
 88→                            />
 89→                        </div>
 90→
 91→                        <div className='form-field'>
 92→                            <label htmlFor='login-password'>Password</label>
 93→                            <div className='input-with-action'>
 94→                                <input
 95→                                    id='login-password'
 96→                                    type={showPass ? 'text' : 'password'}
 97→                                    autoComplete='current-password'
 98→                                    value={password}
 99→                                    onChange={(e) => setPassword(e.target.value)}
100→                                    placeholder='Enter your password'
101→                                    className='auth-input'
102→                                    required
103→                                />
104→                                <button
105→                                    className='show-toggle'
106→                                    type='button'
107→                                    onClick={handleShowPass}
108→                                    aria-label={showPass ? 'Hide password' : 'Show password'}
109→                                >
110→                                    {showPass ? 'Hide' : 'Show'}
111→                                </button>
112→                            </div>
113→                        </div>
114→
115→                        <button className='primary-button' type='submit' disabled={isSubmitDisabled}>
116→                            <span className='button-label'>Log in</span>
117→                            {isLoading && <span className='button-spinner' aria-hidden='true' />}
118→                        </button>
119→
120→                        <button
121→                            className='secondary-button'
122→                            type='button'
123→                            onClick={() => navigate('/home')}
124→                            disabled={isLoading}
125→                        >
126→                            Explore Iskrib
127→                        </button>
128→                    </form>
129→
130→                    <footer className='auth-footer'>
131→                        <span>Don&apos;t have an account?</span>
132→                        <button className='link-button' type='button' onClick={handleNavigate}>
133→                            Sign up
134→                        </button>
135→                    </footer>
136→
137→                    {errorMessage && (
138→                        <div className='form-message error' role='alert'>
139→                            {errorMessage}
140→                        </div>
141→                    )}
142→
143→                    {successMessage && (
144→                        <div className='form-message success' role='status'>
145→                            {successMessage}
146→                        </div>
147→                    )}
148→                </div>
149→            </section>
150→        </div>
151→    );
152→};
153→
154→export default LoginPage;
